const item = $input.first().json || {};
const ex = item.execution || {};
const wf = item.workflow || {};
const err = ex.error || {};
const rawMsg = err.message ?? err.description ?? (typeof ex.error === 'string' ? ex.error : JSON.stringify(ex.error || {}));
return [{
  json: {
    Timestamp: new Date().toISOString(),
    Outcome: 'Error',
    Workflow_Name: String(wf.name || ''),
    Execution_Id: String(ex.id ?? ''),
    Last_Node: String(ex.lastNodeExecuted || ''),
    Detail: '',
    Compliance_Score_Batch: '',
    Parser_Engine_Summary: '',
    Error_Message: String(rawMsg).slice(0, 2000),
    Error_Stack: String(err.stack || '').slice(0, 4000),
    Execution_Url: String(ex.url || '')
  }
}];
